import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Route, Router } from '@angular/router';
import { SponsorshipRequest } from 'src/app/core/models/request.model';
import { RequestService } from 'src/app/core/services/request.service';

@Component({
  selector: 'app-manager-detail',
  templateUrl: './manager-detail.component.html',
  styleUrls: ['./manager-detail.component.css']
})
export class ManagerDetailComponent implements OnInit{
  requestId: number = 0;
  userId: number = 0;
  request: SponsorshipRequest | null = null;
  isLoading = false;
  isSubmitting = false;

  constructor(private route: ActivatedRoute, private router: Router, private requestService: RequestService) {
  }

  ngOnInit(): void {
    this.requestId = Number(this.route.snapshot.paramMap.get('id'));
    this.loadRequestDetails();
  }

  loadRequestDetails() {
    this.isLoading = true;
    this.requestService.getRequestById(this.requestId).subscribe({
      next: (request) => {
        request.status = this.mapStatusToString(Number(request.status));
        this.request = new SponsorshipRequest(request);
        this.isLoading = false;
      },
      error: (error) => {
        console.error('Error:', error);
        this.isLoading = false;
        alert('Error loading request details');
      }
    });
  }

  mapStatusToString(status: number): string {
    const statusMap: { [key: number]: string } = {
      1: 'Draft',
      2: 'PendingManager',
      3: 'PendingFinance',
      4: 'Approved',
      5: 'Rejected',
      6: 'Cancelled'
    };
    return statusMap[status] || 'Draft';
  }

    goBack() {
    this.router.navigate(['/manager/pending']);
  }
}
